 15→/**
 16→ * POST /api/training/{tenant}/module/{moduleIndex}/content
 17→ * Generates content for a specific training module.
 18→ * Idempotent: returns existing content if already generated.
 19→ */
 20→
 21→import { getSnapshot } from "@/config/index";
 22→import { resolveModel } from "@/intake/ai-model-resolver";
 23→import { ProfileRepository } from "@/intake/profile-repository";
 24→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 25→import { ModuleGenerationError, generateModuleContent } from "@/training/module-generator";
 26→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 27→import { StateTransitionError, transitionModule } from "@/training/state-machine";
 28→import type { ModuleContent } from "@/training/types";
 29→import { NextResponse } from "next/server";
 30→
 31→// ---------------------------------------------------------------------------
 32→// Helper — strip server-only fields from module content for client
 33→// ---------------------------------------------------------------------------
 34→
 35→function toClientContent(content: ModuleContent) {
 36→  return {
 37→    ...content,
 38→    scenarios: content.scenarios.map(({ rubric: _rubric, ...s }) => ({
 39→      ...s,
 40→      options: s.options?.map(({ correct: _correct, ...o }) => o),
 41→    })),
 42→    quiz: {
 43→      questions: content.quiz.questions.map(({ rubric: _rubric, ...q }) => ({
 44→        ...q,
 45→        options: q.options?.map(({ correct: _correct, ...o }) => o),
 46→      })),
 47→    },
 48→  };
 49→}
 50→
 51→// ---------------------------------------------------------------------------
 52→// POST handler
 53→// ---------------------------------------------------------------------------
 54→
 55→export async function POST(
 56→  request: Request,
 57→  { params }: { params: Promise<{ tenant: string; moduleIndex: string }> },
 58→) {
 59→  const { tenant: tenantSlug, moduleIndex: moduleIndexStr } = await params;
 60→  const tenantId = request.headers.get("x-tenant-id");
 61→  const employeeId = request.headers.get("x-employee-id");
 62→
 63→  // 1. Auth check
 64→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 65→    return NextResponse.json(
 66→      { error: "unauthorized", message: "Not authenticated" },
 67→      { status: 401 },
 68→    );
 69→  }
 70→
 71→  // 2. Parse and validate moduleIndex
 72→  const moduleIndex = Number(moduleIndexStr);
 73→  if (Number.isNaN(moduleIndex) || moduleIndex < 0 || moduleIndex > 7) {
 74→    return NextResponse.json(
 75→      { error: "invalid_request", message: "Invalid module index" },
 76→      { status: 400 },
 77→    );
 78→  }
 79→
 80→  // Initialise repositories
 81→  const adapter = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 82→  const sessionRepo = new SessionRepository(adapter);
 83→  const profileRepo = new ProfileRepository(adapter);
 84→
 85→  let activeSessionId: string | undefined;
 86→
 87→  try {
 88→    // 3. Find active session
 89→    const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 90→    if (session) activeSessionId = session.id;
 91→    if (!session) {
 92→      return NextResponse.json(
 93→        { error: "not_found", message: "No active training session found" },
 94→        { status: 404 },
 95→      );
 96→    }
 97→
 98→    // 4. Find the module
 99→    const module = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
100→    if (!module) {
101→      return NextResponse.json(
102→        { error: "not_found", message: "Module not found" },
103→        { status: 404 },
104→      );
105→    }
106→
107→    // 5. Idempotent: return existing content if already generated
108→    if (module.content !== null) {
109→      return NextResponse.json(toClientContent(module.content), { status: 200 });
110→    }
111→
112→    // 6. Guard: module must be in `locked` status
113→    if (module.status !== "locked") {
114→      return NextResponse.json(
115→        {
116→          error: "conflict",
117→          message: `Module is in '${module.status}' state, expected 'locked'`,
118→        },
119→        { status: 409 },
120→      );
121→    }
122→
123→    // Guard: previous module must be `scored` (for index > 0)
124→    if (moduleIndex > 0) {
125→      const previousModule = await sessionRepo.findModule(tenantId, session.id, moduleIndex - 1);
126→      if (!previousModule || previousModule.status !== "scored") {
127→        return NextResponse.json(
128→          {
129→            error: "conflict",
130→            message: "Previous module must be scored before generating content",
131→          },
132→          { status: 409 },
133→        );
134→      }
135→    }
136→
137→    // 7. Transition module to `content-generating`
138→    const generatingStatus = transitionModule(module.status, "generate-content");
139→    await sessionRepo.updateModule(
140→      tenantId,
141→      module.id,
142→      { status: generatingStatus },
143→      module.version,
144→    );
145→
146→    // 8. Find confirmed role profile
147→    const roleProfile = await profileRepo.findByEmployee(tenantId, employeeId);
148→    if (!roleProfile) {
149→      return NextResponse.json(
150→        { error: "not_found", message: "Role profile not found" },
151→        { status: 404 },
152→      );
153→    }
154→
155→    // 9. Resolve AI model from tenant config
156→    const snapshot = getSnapshot();
157→    const tenant = snapshot?.tenants.get(tenantSlug);
158→    if (!tenant) {
159→      return NextResponse.json(
160→        { error: "not_found", message: "Tenant not found" },
161→        { status: 404 },
162→      );
163→    }
164→    const model = resolveModel(tenant);
165→
166→    // 10. Generate module content
167→    const moduleOutline = {
168→      title: module.title,
169→      topicArea: module.topicArea,
170→      jobExpectationIndices: module.jobExpectationIndices,
171→    };
172→    const content = await generateModuleContent(moduleOutline, roleProfile, model);
173→
174→    // 11. Update module: set content, transition to `learning`
175→    const learningStatus = transitionModule(generatingStatus, "content-ready");
176→    // Re-fetch module to get updated version after first update
177→    const updatedModule = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
178→    if (!updatedModule) {
179→      return NextResponse.json(
180→        { error: "not_found", message: "Module not found after update" },
181→        { status: 404 },
182→      );
183→    }
184→    await sessionRepo.updateModule(
185→      tenantId,
186→      module.id,
187→      { content, status: learningStatus },
188→      updatedModule.version,
189→    );
190→
191→    // 12. Return 200 with client-safe content
192→    return NextResponse.json(toClientContent(content), { status: 200 });
193→  } catch (error) {
194→    if (error instanceof ModuleGenerationError) {
195→      // Roll back module status to `locked` so future retries are not blocked.
196→      try {
197→        const stuckModule = activeSessionId
198→          ? await sessionRepo.findModule(tenantId, activeSessionId, moduleIndex)
199→          : null;
200→        if (stuckModule && stuckModule.status === "content-generating") {
201→          await sessionRepo.updateModule(
202→            tenantId,
203→            stuckModule.id,
204→            { status: "locked" },
205→            stuckModule.version,
206→          );
207→        }
208→      } catch {
209→        // Best-effort rollback — ignore secondary errors
210→      }
211→      if (error.code === "ai_unavailable") {
212→        return NextResponse.json(
213→          { error: "ai_unavailable", message: "AI service temporarily unavailable" },
214→          { status: 503 },
215→        );
216→      }
217→      return NextResponse.json(
218→        { error: "generation_failed", message: error.message },
219→        { status: 422 },
220→      );
221→    }
222→    if (error instanceof VersionConflictError) {
223→      return NextResponse.json(
224→        { error: "conflict", message: "Resource was modified by another request" },
225→        { status: 409 },
226→      );
227→    }
228→    if (error instanceof StateTransitionError) {
229→      return NextResponse.json({ error: "conflict", message: error.message }, { status: 409 });
230→    }
231→    return NextResponse.json(
232→      { error: "internal_error", message: "An unexpected error occurred" },
233→      { status: 500 },
234→    );
235→  }
236→}
